After creating Catalog, we can manipulate tables through Catalog. You can use the following code to create a table: import ( "github.com/apache/iceberg-go" "github.com/apache/iceberg-go/catalog" "github.com/apache/iceberg-go/table"
) // Create a simple schema
schema := iceberg.NewSchemaWithIdentifiers(1, []int{2}, iceberg.NestedField{ID: 1, Name: "foo", Type: iceberg.PrimitiveTypes.String, Required: false}, iceberg.NestedField{ID: 2, Name: "bar", Type: iceberg.PrimitiveTypes.Int32, Required: true}, iceberg.NestedField{ID: 3, Name: "baz", Type: iceberg.PrimitiveTypes.Bool, Required: false},
) // Create a table identifier
tableIdent := catalog.ToIdentifier("my_namespace", "my_table") // Create a table with optional properties
tbl, err := cat.CreateTable( context.Background(), tableIdent, schema, catalog.WithProperties(map[string]string{"owner": "me"}), catalog.WithLocation("s3://my-bucket/tables/my_table"),
)
if err != nil { log.Fatal(err)
} Also, you can load a table directly: // Load an existing table
tbl, err := cat.LoadTable(context.Background(), tableIdent, nil)
if err != nil { log.Fatal(err)
} fmt.Printf("Table: %s\n", tbl.Identifier())
fmt.Printf("Location: %s\n", tbl.MetadataLocation())

