) // Create schema
schema := iceberg.NewSchemaWithIdentifiers(1, []int{1}, iceberg.NestedField{ID: 1, Name: "id", Type: iceberg.PrimitiveTypes.Int32, Required: true}, iceberg.NestedField{ID: 2, Name: "name", Type: iceberg.PrimitiveTypes.String, Required: false}, iceberg.NestedField{ID: 3, Name: "date", Type: iceberg.PrimitiveTypes.Date, Required: false},
) // Create a partition spec
partitionSpec := iceberg.NewPartitionSpec( iceberg.PartitionField{SourceID: 3, FieldID: 1000, Transform: iceberg.IdentityTransform{}, Name: "date"},
) // Create a table with partitioning
tbl, err := cat.CreateTable( context.Background(), tableIdent, schema, catalog.WithPartitionSpec(&partitionSpec), catalog.WithLocation("s3://my-bucket/tables/partitioned_table"),
)
if err != nil { log.Fatal(err)
}

